@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings

<nav class="settings-sidebar">
    <h3 class="sidebar-title">Settings</h3>
    <ul class="sidebar-nav">
        @foreach (var section in Sections)
        {
            <li class="sidebar-item @(section == ActiveSection ? "active" : "")"
                @onclick="() => OnSectionChanged.InvokeAsync(section)">
                <span class="sidebar-icon">@GetIcon(section)</span>
                <span class="sidebar-label">@section</span>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    private string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings
@using sv_5282321d597f499b8b154392f2d79bdc.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile</h2>

    @if (_profile is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-area">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-preview" />
                <label>Avatar URL</label>
                <input type="text" @bind="_avatarUrl" @bind:event="oninput" class="form-input" />
            </div>

            <div class="form-group">
                <label>Display Name</label>
                <input type="text" @bind="_displayName" class="form-input" />
            </div>

            <div class="form-group">
                <label>Email</label>
                <input type="email" @bind="_email" class="form-input" />
            </div>

            <div class="form-group">
                <label>Bio</label>
                <textarea @bind="_bio" class="form-input form-textarea" rows="4"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Changes</button>
                <button class="btn btn-secondary" @onclick="Discard">Discard Changes</button>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="toast success">@_message</div>
            }
        </div>
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private string? _message;

    protected override async Task OnInitializedAsync()
    {
        _profile = await SettingsService.GetProfileAsync();
        LoadFromProfile(_profile);
    }

    private void LoadFromProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveAsync()
    {
        var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updated);
        _profile = updated;
        _message = "Profile saved successfully!";
        _ = ClearMessageAsync();
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            LoadFromProfile(_profile);
        }
        _message = null;
    }

    private async Task ClearMessageAsync()
    {
        await Task.Delay(3000);
        _message = null;
        StateHasChanged();
    }
}

@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings
@using sv_5282321d597f499b8b154392f2d79bdc.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Notifications</h2>

    @if (_prefs is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="notification-form">
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_emailNotifications" />
                    <span>Email Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_pushNotifications" />
                    <span>Push Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_weeklyDigest" />
                    <span>Weekly Digest</span>
                </label>
            </div>

            <h3>Muted Channels</h3>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="toggle-label">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <span>@channel</span>
                    </label>
                }
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="toast success">@_message</div>
            }
        </div>
    }
</div>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private string? _message;

    private static readonly string[] _allChannels = { "general", "marketing", "engineering", "announcements", "random" };

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        _message = "Preferences saved!";
        _ = ClearMessageAsync();
    }

    private async Task ClearMessageAsync()
    {
        await Task.Delay(3000);
        _message = null;
        StateHasChanged();
    }
}

