@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings
@using sv_5282321d597f499b8b154392f2d79bdc.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Notifications</h2>

    @if (_prefs is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="notification-form">
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_emailNotifications" />
                    <span>Email Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_pushNotifications" />
                    <span>Push Notifications</span>
                </label>
            </div>

            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_weeklyDigest" />
                    <span>Weekly Digest</span>
                </label>
            </div>

            <h3>Muted Channels</h3>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    <label class="toggle-label">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)(e.Value ?? false))" />
                        <span>@channel</span>
                    </label>
                }
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save Preferences</button>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="toast success">@_message</div>
            }
        </div>
    }
</div>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private string? _message;

    private static readonly string[] _allChannels = { "general", "marketing", "engineering", "announcements", "random" };

    protected override async Task OnInitializedAsync()
    {
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(_prefs.MutedChannels);
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(updated);
        _prefs = updated;
        _message = "Preferences saved!";
        _ = ClearMessageAsync();
    }

    private async Task ClearMessageAsync()
    {
        await Task.Delay(3000);
        _message = null;
        StateHasChanged();
    }
}

