@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings
@using sv_5282321d597f499b8b154392f2d79bdc.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Security</h2>

    @if (_settings is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <!-- Change Password Panel -->
        <div class="expandable-panel">
            <button class="panel-header" @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <span>Change Password</span>
                <span class="expand-icon">@(_passwordPanelOpen ? "▼" : "▶")</span>
            </button>
            @if (_passwordPanelOpen)
            {
                <div class="panel-body">
                    <div class="form-group">
                        <label>Current Password</label>
                        <input type="password" @bind="_currentPassword" class="form-input" />
                    </div>
                    <div class="form-group">
                        <label>New Password</label>
                        <input type="password" @bind="_newPassword" class="form-input" />
                    </div>
                    <div class="form-group">
                        <label>Confirm Password</label>
                        <input type="password" @bind="_confirmPassword" class="form-input" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="toast error">@_passwordError</div>
                    }
                    @if (!string.IsNullOrEmpty(_passwordSuccess))
                    {
                        <div class="toast success">@_passwordSuccess</div>
                    }
                    <button class="btn btn-primary" @onclick="ChangePasswordAsync">Update Password</button>
                </div>
            }
        </div>

        <!-- Two-Factor Authentication -->
        <div class="security-item">
            <h3>Two-Factor Authentication</h3>
            <div class="status-row">
                <span class="status-indicator @(_twoFactorEnabled ? "enabled" : "disabled")">
                    @(_twoFactorEnabled ? "● Enabled" : "○ Disabled")
                </span>
                <label class="toggle-label">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span>Enable 2FA</span>
                </label>
            </div>
            @if (_settings.LastPasswordChange.HasValue)
            {
                <p class="meta-text">Last password change: @_settings.LastPasswordChange.Value.ToString("MMM dd, yyyy")</p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="security-item">
            <h3>Active Sessions</h3>
            <table class="sessions-table">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @foreach (var session in _settings.Sessions)
                    {
                        <tr>
                            <td>@session.Device</td>
                            <td>@session.Location</td>
                            <td>@FormatLastActive(session.LastActive)</td>
                            <td>
                                @if (session.Id != _currentSessionId)
                                {
                                    <button class="btn btn-danger btn-sm" @onclick="() => PromptRevoke(session)">
                                        Revoke
                                    </button>
                                }
                                else
                                {
                                    <span class="meta-text">Current</span>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>

        <!-- Revoke Confirmation Dialog -->
        @if (_sessionToRevoke is not null)
        {
            <div class="dialog-overlay" @onclick="CancelRevoke">
                <div class="dialog" @onclick:stopPropagation="true">
                    <h3>Revoke Session</h3>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="dialog-actions">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeAsync">Revoke</button>
                        <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    </div>
                </div>
            </div>
        }
    }
</div>

@code {
    private SecuritySettings? _settings;
    private bool _passwordPanelOpen;
    private bool _twoFactorEnabled;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private string? _passwordSuccess;
    private ActiveSession? _sessionToRevoke;

    // First session is treated as "current"
    private string _currentSessionId = "sess-1";

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _twoFactorEnabled = _settings.TwoFactorEnabled;
    }

    private async Task ChangePasswordAsync()
    {
        _passwordError = null;
        _passwordSuccess = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _passwordError = "Current password is required.";
            return;
        }
        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "New password is required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "Passwords do not match.";
            return;
        }

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
        _passwordSuccess = "Password updated successfully!";
        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _settings = await SettingsService.GetSecuritySettingsAsync();
    }

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevokeAsync()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _settings = await SettingsService.GetSecuritySettingsAsync();
            _sessionToRevoke = null;
        }
    }

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours} hours ago";
        return $"{(int)diff.TotalDays} days ago";
    }
}

