@namespace sv_5282321d597f499b8b154392f2d79bdc.Components.Pages.Settings
@using sv_5282321d597f499b8b154392f2d79bdc.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance</h2>

    @if (_settings is null)
    {
        <p>Loading...</p>
    }
    else
    {
        <div class="appearance-form">
            <!-- Theme -->
            <div class="form-group">
                <label class="group-label">Theme</label>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Font Size -->
            <div class="form-group">
                <label class="group-label">Font Size</label>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-label">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <!-- Language -->
            <div class="form-group">
                <label class="group-label">Language</label>
                <select @bind="_language" class="form-input form-select">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="toggle-group">
                <label class="toggle-label">
                    <input type="checkbox" @bind="_compactMode" />
                    <span>Compact Mode</span>
                </label>
            </div>

            <!-- Live Preview -->
            <div class="preview-area @GetPreviewClasses()">
                <h4>Live Preview</h4>
                <p class="preview-text">This is how your content will look with the selected settings.</p>
                <div class="preview-card">
                    <strong>Sample Card</strong>
                    <p>A quick notification message appears here.</p>
                </div>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAsync">Save</button>
            </div>

            @if (!string.IsNullOrEmpty(_message))
            {
                <div class="toast success">@_message</div>
            }
        </div>
    }
</div>

@code {
    private AppearanceSettings? _settings;
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private string? _message;

    private static readonly string[] _themes = { "Light", "Dark", "System" };
    private static readonly string[] _fontSizes = { "Small", "Medium", "Large" };
    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese" };

    protected override async Task OnInitializedAsync()
    {
        _settings = await SettingsService.GetAppearanceAsync();
        _theme = _settings.Theme;
        _fontSize = _settings.FontSize;
        _language = _settings.Language;
        _compactMode = _settings.CompactMode;
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add($"preview-theme-{_theme.ToLowerInvariant()}");
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private async Task SaveAsync()
    {
        var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(updated);
        _settings = updated;
        _message = "Appearance saved!";
        _ = ClearMessageAsync();
    }

    private async Task ClearMessageAsync()
    {
        await Task.Delay(3000);
        _message = null;
        StateHasChanged();
    }
}

